-- ============================================
-- books-shop 더미데이터
-- PostgreSQL
-- categories 3건 + books 45건
-- books.id 형식: IT-키워드-UUID6 (예: IT-NV-A1B2C3)
-- 주의: 가격/재고/설명은 실습용 임의 데이터입니다.
-- cover_image는 교보문고 CDN의 ISBN 기반 표지 URL 형식입니다.
-- ============================================

-- 기존 데이터가 있다면 FK 순서 때문에 books 먼저 삭제
-- DELETE FROM books;
-- DELETE FROM categories;

INSERT INTO categories (
    id, name, types, description, display_order, use_yn, created_at, updated_at
) VALUES
      ('CA-23A751917858451E', 'IT 서적', 'IT', '프로그래밍, 데이터베이스, 웹 개발 관련 도서', 1, 'Y', now(), now()),
      ('CA-F45EEA43BBA3415B', '소설', 'NOVEL', '국내외 장편소설 및 문학 도서', 2, 'Y', now(), now()),
      ('CA-36D7EB2233D240FC', '자기계발도서', 'SELF', '습관, 커리어, 돈, 관계, 성장 관련 도서', 3, 'Y', now(), now())
    ON CONFLICT (name) DO NOTHING;

